$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_9694d0be97bf968cc2f675626539b481'] = 'Esta configuração não irá ficar ativa, ative-a apenas uma vez para verificar o seu tema. Depois de rever isto, os dados ausentes serão mostrados abaixo';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_3efd013facfe95e35bf3e06d76f2e1cf'] = 'Este processo é feito automaticamente na instalação do módulo e só precisa de ativá-lo se tiver alterado o seu tema ou a estrutura do tema.';
