$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_7fb1257954aaa784b2b594423245382d'] = 'Dependendo da página, do servidor e de outros factores, diferentes páginas podem beneficiar de diferentes definições.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_c40afb7e4fda9e27814632326c559518'] = 'Estas são as opções disponíveis:';
