$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_40e3b703725ac945e663f2c6b1ba3402'] = 'o módulo tenta carregar o pixel no rodapé para não bloquear o tempo de carregamento. O seu tema deve utilizar o hook do rodapé';
