$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_69d907e9a73fd1666195d7ee39ff1ed2'] = 'Também pode forçá-lo no cabeçalho para tirar partido do carregamento assíncrono. Isso pode acelerar o tempo de carregamento e reduzir o tempo de carregamento da página na maioria dos casos';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_4729077ae098f429def9fe9a41de0a39'] = 'Carregamento diferido';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_30327841e3afbdd1e3a14a2cf328570e'] = 'Esta terceira opção permitecarregar o píxel depois de a página estar completamente carregada. Em alguns casos, esta opção pode reduzir bastante o tempo de carregamento da página, mas tem a contrapartida de que qualquer ação antes do carregamento do pixel não será rastreada';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_71c6dc1af52ebbfa10df384604a8a9e3'] = 'Diferir apenas a primeira vez';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_12f9dfc9f516d3bb7dda55cf5a31f004'] = 'É altamente recomendável se utilizar o modo de adiamento. Isto limitará o adiamento à primeira vez, pelo que, assim que o script for carregado na cache do browser, o script será carregado sem demora e, por conseguinte, todas as acções estarão prontas a um ritmo mais rápido';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_5375c3b82e74b580e0e204e6dd2688ea'] = 'Forçar pixels no cabeçalho';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_c7f846b5f8b98ab8b04139d46ed97d77'] = 'O módulo tenta colocar os pixels no rodapé da página, desta maneira o JS não bloqueia a renderização da página';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_2a15dc4f3f26cd90b90668d455cfdae3'] = 'desta forma o cliente sente que a página carrega mais depressa e assim também melhora o SEO da página';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_663d0f6013ed5ef549d45f58efc1ce79'] = 'Alguns temas e páginas personalizadas não têm ligação de rodapé, se este for o seu caso, ative esta opção';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_1f0e6e698597ac3693839450078045cf'] = 'Ativar esta definição para carregar o píxel apenas depois de a página ser carregada';
