$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_5844921378c6e171981c0bb09f8d3d4c'] = 'Quantos segundos depois de a página estar completamente carregada deve o script esperar para ser carregado, valor recomendado 2-3 segundos';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_b46a6315be8aedecadb4f78597c064da'] = 'Apenas são permitidos valores inteiros.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_577140e94105d4437264092c669a9c6f'] = 'O Facebook garante que o script fb_evens.js só será descarregado na primeira vez e, depois disso, será carregado a partir da cache. Isto significa que, teoricamente, apenas na primeira vez devemos aplicar a opção de adiamento, uma vez que as seguintes não demorarão a ser descarregadas.';
