$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_4e15b0b357e2427f306fd8f61e1a56dc'] = 'Por padrão, o módulo não retransmite na página de agradecimento para exibir o evento Purchase, isso o torna compatível com qualquer módulo de pagamento, independentemente da página de retorno após o pagamento, mas os mecanismos de cache tendem a armazenar em cache a saída do módulo, repetindo quando não for necessário.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_53f0d8f2e081eb6375416a5331275d5a'] = 'Quando isso acontecer, ative a opção avançada ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_5d167d92ce03c8db70da784b1b5001b4'] = 'Mas alguns caches são bastante pesados e podem estar ignorando a tela tripla que o módulo aplica';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_f7cee7aa810ddefb08c52bd6693b39c5'] = 'Certo! O pixel do Facebook é inicializado no cabeçalho da página, o que significa que você pode acionar (enviar) um evento em qualquer página. Isso é útil quando você deseja adicionar o evento Lead, por exemplo, vinculando-o a um certo botão.';
